async function tableHasDocColumn(client, tableName) {
  const res = await client.query(
    `SELECT 1 FROM information_schema.columns WHERE table_name = $1 AND column_name = 'doc'`,
    [tableName]
  );
  return res.rowCount > 0;
}

export async function ensureSchema(client) {
  // Drop and recreate tables only if they lack the JSONB doc column (migration from normalized schema).
  for (const table of ['invoices', 'orders', 'accounts']) {
    const hasDoc = await tableHasDocColumn(client, table);
    if (!hasDoc) {
      await client.query(`DROP TABLE IF EXISTS ${table} CASCADE`);
    }
  }
